function loadOptionalEnv<const TKey extends string>(
	env: NodeJS.ProcessEnv,
	keys: readonly TKey[],
): Partial<Record<TKey, string>> {
	const values = {} as Partial<Record<TKey, string>>;

	for (const key of keys) {
		const value = env[key];

		if (value?.trim()) {
			values[key] = value;
		}
	}

	return values;
}

