async function prepareSourceInSandbox({
	sandbox,
	repositoryUrl,
	branchName,
}: {
	sandbox: RhapsodyVercelSandbox;
	repositoryUrl: string;
	branchName: string;
}): Promise<SourcePreparationSummary> {
	await runVercelSandboxCommand(sandbox, {
		cmd: "rm",
		args: ["-rf", REPOSITORY_PATH],
		cwd: SANDBOX_WORKDIR,
	});

