		cmd: "git",
		args: ["clone", "--depth", "1", repositoryUrl, REPOSITORY_PATH],
		cwd: SANDBOX_WORKDIR,
	});

	if (cloneCommand.exitCode !== 0) {
		return {
			success: false,
			cloneCommand,
			checkoutCommand: null,
		};
	}

	const checkoutCommand = await runVercelSandboxCommand(sandbox, {
		cmd: "git",
		args: ["-C", REPOSITORY_PATH, "checkout", "-B", branchName],
		cwd: SANDBOX_WORKDIR,
	});

